// Admin Users page
import React, { useEffect, useState } from 'react';
import { adminAPI } from '../../utils/api';
import Spinner, { StatusBadge } from '../../components/common/Spinner';
import toast from 'react-hot-toast';

export default function AdminUsers() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');

  useEffect(() => { adminAPI.getUsers().then(({ data }) => setUsers(data.users)).finally(() => setLoading(false)); }, []);

  const toggle = async (id) => {
    const { data } = await adminAPI.toggleUser(id);
    setUsers(prev => prev.map(u => u._id === id ? data.user : u));
    toast.success('User status updated');
  };

  const filtered = users.filter(u => u.name.toLowerCase().includes(search.toLowerCase()) || u.email.toLowerCase().includes(search.toLowerCase()));

  if (loading) return <Spinner />;

  return (
    <div>
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '1.5rem' }}>
        <h1 style={{ fontSize: '1.5rem' }}>Users ({users.length})</h1>
        <input className="form-control" placeholder="🔍 Search users..." style={{ width: 280 }} value={search} onChange={e => setSearch(e.target.value)} />
      </div>
      <div className="card" style={{ overflow: 'hidden' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead>
            <tr style={{ background: 'var(--gray-50)', borderBottom: '2px solid var(--gray-200)' }}>
              {['User', 'Email', 'Role', 'Status', 'Joined', 'Actions'].map(h => (
                <th key={h} style={{ padding: '0.85rem 1rem', textAlign: 'left', fontSize: '0.78rem', fontWeight: 700, color: 'var(--gray-600)', textTransform: 'uppercase', letterSpacing: '0.05em' }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filtered.map(u => (
              <tr key={u._id} style={{ borderBottom: '1px solid var(--gray-100)' }}>
                <td style={{ padding: '0.85rem 1rem' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '0.6rem' }}>
                    <img src={u.avatar} alt={u.name} style={{ width: 36, height: 36, borderRadius: '50%' }} />
                    <strong style={{ fontSize: '0.875rem' }}>{u.name}</strong>
                  </div>
                </td>
                <td style={{ padding: '0.85rem 1rem', fontSize: '0.875rem', color: 'var(--gray-600)' }}>{u.email}</td>
                <td style={{ padding: '0.85rem 1rem' }}><span className="badge badge-green" style={{ textTransform: 'capitalize' }}>{u.role}</span></td>
                <td style={{ padding: '0.85rem 1rem' }}><StatusBadge status={u.isActive ? 'active' : 'inactive'} /></td>
                <td style={{ padding: '0.85rem 1rem', fontSize: '0.8rem', color: 'var(--gray-500)' }}>{new Date(u.createdAt).toLocaleDateString()}</td>
                <td style={{ padding: '0.85rem 1rem' }}>
                  {u.role !== 'admin' && (
                    <button className={`btn btn-sm ${u.isActive ? 'btn-danger' : 'btn-secondary'}`} onClick={() => toggle(u._id)}>
                      {u.isActive ? 'Deactivate' : 'Activate'}
                    </button>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
